"use client";

import { Radio, type RadioProps } from "./radio";
import {
  RadioGroup as RadioGroupRoot,
  type RadioGroupActivationMode,
  type RadioGroupBoundaryDirection,
  type RadioGroupNavigationDirection,
  type RadioGroupProps,
} from "./radio-group";
import { RadioGroupItem, type RadioGroupItemProps } from "./radio-group-item";

const RadioGroup = Object.assign(RadioGroupRoot, {
  Item: RadioGroupItem,
});

export { Radio, type RadioProps };
export {
  RadioGroup,
  type RadioGroupActivationMode,
  type RadioGroupBoundaryDirection,
  type RadioGroupNavigationDirection,
  type RadioGroupProps,
};
export { RadioGroupItem, type RadioGroupItemProps };

"use client";

import {
  type ComponentPropsWithRef,
  type AriaAttributes,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
  type ReactNode,
  type Ref,
  type KeyboardEvent as ReactKeyboardEvent,
} from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { useFormReset } from "@/hooks/use-form-reset";
import { useNavigation } from "@/hooks/use-navigation";
import { composeRefs } from "@/lib/compose-refs";
import {
  getEnabledSelectableCollectionItems,
  getSelectableCollectionItemValue,
  resolveSelectableCollectionItem,
  resolveSelectableCollectionItemValue,
  useSelectableCollection,
} from "@/lib/selectable-collection";
import { cn } from "@/lib/utils";
import type { RadioSize } from "./radio";
import type { SelectableVariant } from "@/lib/selectable-variants";
import { RadioGroupContext, type RadioGroupContextValue } from "./radio-group-context";

type RadioGroupRootProps = Omit<
  ComponentPropsWithRef<"div">,
  | "children"
  | "role"
  | "onChange"
  | "onKeyDown"
  | "className"
  | "ref"
  | "aria-label"
  | "aria-labelledby"
  | "aria-orientation"
  | "aria-required"
  | "aria-invalid"
  | "aria-disabled"
>;

export interface RadioGroupProps extends RadioGroupRootProps {
  value?: string;
  defaultValue?: string;
  onChange?: (value: string) => void;
  onNavigate?: (value: string, direction: RadioGroupNavigationDirection) => void;
  onEnter?: (value: string, event: ReactKeyboardEvent<HTMLDivElement>) => void;
  onHighlightChange?: (value: string | null) => void;
  onKeyDown?: (event: ReactKeyboardEvent) => void;
  highlighted?: string | null;
  orientation?: "vertical" | "horizontal";
  wrap?: boolean;
  keyboardNavigation?: boolean;
  activationMode?: RadioGroupActivationMode;
  onNavigationBoundaryReached?: (
    direction: RadioGroupBoundaryDirection,
    event: globalThis.KeyboardEvent,
    key: string,
  ) => void;
  disabled?: boolean;
  autoFocus?: boolean;
  size?: RadioSize;
  variant?: SelectableVariant;
  name?: string;
  required?: boolean;
  label?: string;
  "aria-label"?: string;
  "aria-labelledby"?: string;
  "aria-invalid"?: AriaAttributes["aria-invalid"];
  className?: string;
  children: ReactNode;
  ref?: Ref<HTMLDivElement>;
}

export type RadioGroupActivationMode = "automatic" | "manual";
export type RadioGroupBoundaryDirection = "previous" | "next";
export type RadioGroupNavigationDirection = "previous" | "next" | "first" | "last";

const RADIO_PREVIOUS_KEYS = ["ArrowUp", "ArrowLeft"] as const;
const RADIO_NEXT_KEYS = ["ArrowDown", "ArrowRight"] as const;

function isHTMLElementForContainer(value: unknown, container: HTMLElement | null): value is HTMLElement {
  const View = container?.ownerDocument.defaultView;
  return Boolean(View && value instanceof View.HTMLElement);
}

function getRadioNavigationDirection(key: string): RadioGroupNavigationDirection | null {
  if (key === "ArrowUp" || key === "ArrowLeft") return "previous";
  if (key === "ArrowDown" || key === "ArrowRight") return "next";
  if (key === "Home") return "first";
  if (key === "End") return "last";
  return null;
}

function resolveGroupAriaInvalid(
  forceInvalid: boolean | undefined,
  ariaInvalid: AriaAttributes["aria-invalid"],
) {
  if (forceInvalid) return true;
  if (ariaInvalid === true || ariaInvalid === "true" || ariaInvalid === "grammar" || ariaInvalid === "spelling") {
    return ariaInvalid;
  }
  if (ariaInvalid === false || ariaInvalid === "false") return ariaInvalid;
  return undefined;
}

export function RadioGroup(props: RadioGroupProps) {
  const {
    value: controlledValue,
    defaultValue,
    onChange,
    onNavigate,
    onEnter,
    onHighlightChange,
    onKeyDown,
    highlighted: controlledHighlighted,
    orientation = "vertical",
    wrap = true,
    keyboardNavigation = true,
    activationMode = "automatic",
    onNavigationBoundaryReached,
    disabled = false,
    autoFocus = false,
    size = "md",
    variant = "bullet",
    name,
    required,
    label,
    "aria-label": ariaLabel,
    "aria-labelledby": ariaLabelledBy,
    "aria-invalid": ariaInvalid,
    className,
    children,
    ref,
    ...rootProps
  } = props;
  const containerRef = useRef<HTMLDivElement>(null);
  const hasAutoFocusedRef = useRef(false);
  const navigationEventRef = useRef<ReactKeyboardEvent<HTMLDivElement> | null>(null);
  const { items, registerItem, unregisterItem } = useSelectableCollection(containerRef);
  const [requiredInvalid, setRequiredInvalid] = useState(false);

  const [value, setValue] = useControllableState<string | undefined>({
    value: controlledValue,
    controlled: "value" in props,
    defaultValue,
    onChange: (next) => {
      if (next !== undefined) onChange?.(next);
    },
  });
  useFormReset(containerRef, defaultValue, setValue, !("value" in props));

  const [highlightedValue, setHighlightedValue] = useControllableState<string | null>({
    value: controlledHighlighted,
    controlled: "highlighted" in props,
    defaultValue: null,
    onChange: onHighlightChange,
  });

  const enabledItems = getEnabledSelectableCollectionItems(items, disabled);
  const validHighlightedValue = getSelectableCollectionItemValue(enabledItems, highlightedValue);
  const validSelectedValue = getSelectableCollectionItemValue(enabledItems, value);
  const tabTargetValue = activationMode === "manual"
    ? resolveSelectableCollectionItemValue(enabledItems, highlightedValue, value)
    : resolveSelectableCollectionItemValue(enabledItems, value, highlightedValue);

  useEffect(() => {
    if (!autoFocus || !keyboardNavigation || disabled) {
      hasAutoFocusedRef.current = false;
      return;
    }
    if (hasAutoFocusedRef.current) return;

    const activeItems = getEnabledSelectableCollectionItems(items, disabled);
    const target = resolveSelectableCollectionItem(activeItems, highlightedValue, value);
    if (!target?.element) return;

    target.element.focus();
    setHighlightedValue(target.value);
    hasAutoFocusedRef.current = true;
  }, [autoFocus, keyboardNavigation, disabled, items, highlightedValue, value, setHighlightedValue]);

  const handleValueChange = useCallback((next: string) => {
    setRequiredInvalid(false);
    setValue(next);
  }, [setValue]);

  const handleRequiredInvalid = useCallback(() => {
    setRequiredInvalid(true);
  }, []);

  const handleNavigatedItem = useCallback((next: string | null) => {
    if (next === null) return;
    setHighlightedValue(next);
    setRequiredInvalid(false);

    const direction = getRadioNavigationDirection(navigationEventRef.current?.key ?? "");
    if (direction !== null) onNavigate?.(next, direction);

    if (activationMode === "automatic") setValue(next);
  }, [activationMode, onNavigate, setHighlightedValue, setValue]);

  const handleNavigationEnter = useCallback((next: string) => {
    const event = navigationEventRef.current;
    if (!event) return;

    setHighlightedValue(next);
    handleValueChange(next);
    onEnter?.(next, event);
  }, [handleValueChange, onEnter, setHighlightedValue]);

  const handleNavigationBoundaryReached = useCallback((
    direction: RadioGroupBoundaryDirection,
    event: globalThis.KeyboardEvent,
    key: string,
  ) => {
    onNavigationBoundaryReached?.(direction, event, key);
  }, [onNavigationBoundaryReached]);

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "radio",
    highlighted: tabTargetValue,
    onHighlightChange: handleNavigatedItem,
    onEnter: handleNavigationEnter,
    wrap,
    enabled: keyboardNavigation && !disabled,
    moveFocus: true,
    scopeToContainer: true,
    upKeys: RADIO_PREVIOUS_KEYS,
    downKeys: RADIO_NEXT_KEYS,
    onNavigationBoundaryReached: handleNavigationBoundaryReached,
  });

  const handleKeyDown = (event: ReactKeyboardEvent<HTMLDivElement>) => {
    const eventTarget = isHTMLElementForContainer(event.target, containerRef.current)
      ? event.target
      : null;
    if (
      eventTarget
      && eventTarget.closest('[role="radiogroup"]') !== containerRef.current
    ) {
      return;
    }

    onKeyDown?.(event);
    if (event.defaultPrevented || !keyboardNavigation || disabled) return;

    navigationEventRef.current = event;
    try {
      navKeyDown(event);
    } finally {
      navigationEventRef.current = null;
    }
  };

  const contextValue: RadioGroupContextValue = useMemo(() => ({
    value,
    onChange: handleValueChange,
    registerItem,
    unregisterItem,
    disabled,
    keyboardNavigation,
    size,
    variant,
    highlightedValue: validHighlightedValue,
    name,
    required,
    onRequiredInvalid: handleRequiredInvalid,
    tabTargetValue,
  }), [value, handleValueChange, registerItem, unregisterItem, disabled, keyboardNavigation, size, variant, validHighlightedValue, name, required, handleRequiredInvalid, tabTargetValue]);

  return (
    <RadioGroupContext value={contextValue}>
      {required && !name && (
        <input
          type="checkbox"
          required
          checked={validSelectedValue !== null}
          disabled={disabled}
          tabIndex={-1}
          aria-hidden={true}
          aria-label={ariaLabel ?? label}
          readOnly
          className="sr-only"
          onInvalid={(event) => {
            event.preventDefault();
            handleRequiredInvalid();
            enabledItems[0]?.element?.focus();
          }}
        />
      )}
      <div
        {...rootProps}
        ref={composeRefs(containerRef, ref)}
        role="radiogroup"
        data-diffgazer-selectable-owner="radio"
        aria-label={ariaLabel ?? label}
        aria-labelledby={ariaLabelledBy}
        aria-orientation={orientation}
        aria-required={required || undefined}
        aria-invalid={resolveGroupAriaInvalid(requiredInvalid && validSelectedValue === null, ariaInvalid)}
        aria-disabled={disabled || undefined}
        className={cn(
          "flex",
          orientation === "vertical" ? "flex-col gap-2" : "flex-row gap-4",
          className
        )}
        onKeyDown={handleKeyDown}
      >
        {children}
      </div>
    </RadioGroupContext>
  );
}

"use client";

import {
  useCallback,
  useEffect,
  useId,
  useRef,
  useState,
  type AriaAttributes,
  type ComponentPropsWithRef,
  type KeyboardEvent as ReactKeyboardEvent,
  type MouseEvent as ReactMouseEvent,
  type ReactNode,
  type Ref,
} from "react";
import { useControllableState } from "@/hooks/use-controllable-state";
import { useFormReset } from "@/hooks/use-form-reset";
import { composeRefs } from "@/lib/compose-refs";
import {
  selectableVariants,
  selectableContainerClass,
  selectableIndicatorVariants,
  selectableLabelVariants,
  selectableDescriptionVariants,
  selectableIndicators,
  type SelectableSize,
  type SelectableVariant,
} from "@/lib/selectable-variants";
import { cn } from "@/lib/utils";

export type RadioSize = SelectableSize;

const RADIO_CHECK_EVENT = "diffgazer:radio-check";

function resolveAriaInvalid(
  forceInvalid: boolean | undefined,
  ariaInvalid: AriaAttributes["aria-invalid"],
) {
  if (forceInvalid) return true;
  if (ariaInvalid === true || ariaInvalid === "true" || ariaInvalid === "grammar" || ariaInvalid === "spelling") {
    return ariaInvalid;
  }
  if (ariaInvalid === false || ariaInvalid === "false") return ariaInvalid;
  return undefined;
}

function mergeIds(...values: Array<string | undefined>) {
  const ids = values.flatMap((value) => value?.split(/\s+/).filter(Boolean) ?? []);
  return ids.length > 0 ? ids.join(" ") : undefined;
}

interface RadioCheckEventDetail {
  name: string;
  form: HTMLFormElement | null;
  source: HTMLElement;
}

function dispatchRadioCheck(source: HTMLElement, name: string) {
  source.ownerDocument.dispatchEvent(new CustomEvent<RadioCheckEventDetail>(RADIO_CHECK_EVENT, {
    detail: {
      name,
      form: source.closest("form"),
      source,
    },
  }));
}

type RadioRootProps = Omit<
  ComponentPropsWithRef<"div">,
  | "children"
  | "role"
  | "aria-checked"
  | "aria-disabled"
  | "aria-invalid"
  | "aria-label"
  | "aria-labelledby"
  | "aria-describedby"
  | "tabIndex"
  | "onChange"
  | "className"
  | "ref"
  | "data-value"
>;

export interface RadioProps extends RadioRootProps {
  checked?: boolean;
  defaultChecked?: boolean;
  isTabTarget?: boolean;
  onChange?: (checked: boolean) => void;
  label?: ReactNode;
  description?: ReactNode;
  disabled?: boolean;
  highlighted?: boolean;
  size?: RadioSize;
  name?: string;
  value?: string;
  required?: boolean;
  variant?: SelectableVariant;
  "aria-label"?: string;
  "aria-labelledby"?: string;
  "aria-describedby"?: string;
  "aria-invalid"?: AriaAttributes["aria-invalid"];
  onNativeInvalid?: () => void;
  className?: string;
  ref?: Ref<HTMLDivElement>;
  "data-value"?: string;
}

export function Radio({
  checked,
  defaultChecked = false,
  isTabTarget = true,
  onChange,
  onClick,
  onKeyDown,
  onMouseEnter,
  label,
  description,
  disabled = false,
  highlighted = false,
  size = "md",
  variant = "bullet",
  name,
  value = "on",
  required,
  "aria-label": ariaLabel,
  "aria-labelledby": ariaLabelledBy,
  "aria-describedby": ariaDescribedBy,
  "aria-invalid": ariaInvalid,
  onNativeInvalid,
  className,
  ref,
  "data-value": dataValue,
  ...rootProps
}: RadioProps) {
  const generatedId = useId();
  const labelId = `${generatedId}-label`;
  const descriptionId = `${generatedId}-desc`;

  const rootRef = useRef<HTMLDivElement>(null);
  const [isChecked, setIsChecked, isControlled] = useControllableState<boolean>({
    value: checked,
    defaultValue: defaultChecked,
    onChange,
  });
  const [nativeInvalid, setNativeInvalid] = useState(false);
  const resolvedAriaInvalid = resolveAriaInvalid(nativeInvalid && required && !isChecked, ariaInvalid);
  const resolvedAriaLabelledBy = ariaLabel
    ? undefined
    : mergeIds(ariaLabelledBy, label ? labelId : undefined);
  const resolvedAriaDescribedBy = mergeIds(
    ariaDescribedBy,
    description ? descriptionId : undefined,
  );

  useFormReset(rootRef, defaultChecked, setIsChecked, checked === undefined);

  const notifySameNameRadios = useCallback(() => {
    if (!name || !rootRef.current) return;
    dispatchRadioCheck(rootRef.current, name);
  }, [name]);

  useEffect(() => {
    if (!name || isControlled) return;

    const ownerDocument = rootRef.current?.ownerDocument;
    if (!ownerDocument) return;

    const handleRadioCheck = (event: Event) => {
      const detail = (event as CustomEvent<Partial<RadioCheckEventDetail> | undefined>).detail;
      if (
        !detail ||
        detail.name !== name ||
        detail.source === rootRef.current ||
        detail.form !== (rootRef.current?.closest("form") ?? null)
      ) {
        return;
      }

      setIsChecked(false);
    };

    ownerDocument.addEventListener(RADIO_CHECK_EVENT, handleRadioCheck);
    return () => ownerDocument.removeEventListener(RADIO_CHECK_EVENT, handleRadioCheck);
  }, [isControlled, name, setIsChecked]);

  useEffect(() => {
    if (isChecked) notifySameNameRadios();
  }, [isChecked, notifySameNameRadios]);

  const toggle = () => {
    if (disabled) return;
    setNativeInvalid(false);
    setIsChecked(true);
  };

  const handleClick = (event: ReactMouseEvent<HTMLDivElement>) => {
    if (disabled) {
      event.preventDefault();
      return;
    }
    onClick?.(event);
    if (!event.defaultPrevented) toggle();
  };

  const handleKeyDown = (e: ReactKeyboardEvent<HTMLDivElement>) => {
    if (disabled) {
      e.preventDefault();
      return;
    }
    onKeyDown?.(e);
    if (e.defaultPrevented) return;
    if (e.key === " ") {
      e.preventDefault();
      toggle();
    }
  };

  return (
    <>
      {(name || required) && (
        <input
          type="radio"
          name={name}
          value={value}
          checked={isChecked}
          required={required}
          disabled={disabled}
          className="sr-only"
          tabIndex={-1}
          readOnly
          aria-hidden={true}
          aria-label={ariaLabel ?? (typeof label === "string" ? label : name)}
          onInvalid={(event) => {
            event.preventDefault();
            onNativeInvalid?.();
            if (!onNativeInvalid) setNativeInvalid(true);
            const group = rootRef.current?.closest('[role="radiogroup"]');
            const owner = group?.querySelector<HTMLElement>('[role="radio"]:not([aria-disabled="true"])');
            (owner ?? rootRef.current)?.focus();
          }}
        />
      )}
      <div
        {...rootProps}
        ref={composeRefs(rootRef, ref)}
        role="radio"
        data-value={dataValue ?? value}
        data-highlighted={highlighted ? "true" : undefined}
        aria-checked={isChecked}
        aria-disabled={disabled || undefined}
        aria-invalid={resolvedAriaInvalid}
        aria-label={ariaLabel}
        aria-labelledby={resolvedAriaLabelledBy}
        aria-describedby={resolvedAriaDescribedBy}
        tabIndex={!disabled && isTabTarget ? 0 : -1}
        onClick={handleClick}
        onKeyDown={handleKeyDown}
        onMouseEnter={onMouseEnter}
        className={cn(
          selectableVariants({ highlighted, disabled }),
          selectableContainerClass,
          description && "items-start",
          className
        )}
      >
        <span
          aria-hidden="true"
          className={selectableIndicatorVariants({
            size,
            checked: isChecked,
            highlighted,
          })}
        >
          {selectableIndicators[variant][isChecked ? "checked" : "unchecked"]}
        </span>
        {label && (
          <div
            className={cn(
              "flex flex-col min-w-0",
              !description && "justify-center"
            )}
          >
            <span id={labelId} className={selectableLabelVariants({ size })}>{label}</span>
            {description && (
              <span id={descriptionId} className={selectableDescriptionVariants({ highlighted })}>
                {description}
              </span>
            )}
          </div>
        )}
      </div>
    </>
  );
}

"use client";

import { useId, useLayoutEffect, useRef, type ReactNode } from "react";
import { useRadioGroupContext } from "./radio-group-context";
import { Radio, type RadioProps } from "./radio";
import { composeRefs } from "@/lib/compose-refs";

export interface RadioGroupItemProps
  extends Omit<
    RadioProps,
    | "checked"
    | "defaultChecked"
    | "isTabTarget"
    | "onChange"
    | "highlighted"
    | "size"
    | "variant"
    | "name"
    | "required"
    | "onNativeInvalid"
    | "value"
    | "data-value"
  > {
  value: string;
  label: ReactNode;
  description?: ReactNode;
  disabled?: boolean;
}

export function RadioGroupItem({
  value,
  label,
  description,
  disabled: itemDisabled,
  ref,
  ...radioProps
}: RadioGroupItemProps) {
  const context = useRadioGroupContext();
  const itemId = useId();
  const rootRef = useRef<HTMLDivElement>(null);
  const isSelected = context.value === value;
  const isDisabled = context.disabled || !!itemDisabled;
  const isHighlighted = context.highlightedValue === value;
  const isTabTarget = !isDisabled && (!context.keyboardNavigation || context.tabTargetValue === value);
  const { registerItem, unregisterItem } = context;

  useLayoutEffect(() => {
    registerItem(itemId, value, itemDisabled === true, rootRef.current);
    return () => unregisterItem(itemId);
  }, [registerItem, unregisterItem, itemId, value, itemDisabled]);

  return (
    <Radio
      {...radioProps}
      ref={composeRefs(rootRef, ref)}
      data-value={value}
      value={value}
      checked={isSelected}
      isTabTarget={isTabTarget}
      onChange={() => context.onChange(value)}
      label={label}
      description={description}
      disabled={isDisabled}
      highlighted={isHighlighted}
      size={context.size}
      variant={context.variant}
      name={context.name}
      required={context.name ? context.required : undefined}
      onNativeInvalid={context.onRequiredInvalid}
    />
  );
}

"use client";

import { createContext, useContext } from "react";
import type { RadioSize } from "./radio";
import type { SelectableVariant } from "@/lib/selectable-variants";

export interface RadioGroupContextValue {
  value?: string;
  onChange: (value: string) => void;
  registerItem: (itemId: string, itemValue: string, disabled: boolean, element: HTMLElement | null) => void;
  unregisterItem: (itemId: string) => void;
  disabled: boolean;
  keyboardNavigation: boolean;
  size: RadioSize;
  variant: SelectableVariant;
  highlightedValue: string | null;
  name?: string;
  required?: boolean;
  onRequiredInvalid: () => void;
  tabTargetValue: string | null;
}

export const RadioGroupContext = createContext<RadioGroupContextValue | undefined>(undefined);

export function useRadioGroupContext() {
  const context = useContext(RadioGroupContext);
  if (!context) {
    throw new Error("RadioGroupItem must be used within RadioGroup");
  }
  return context;
}
